const weather = $json;

const toDateList = (arr) =>
  Array.isArray(arr) ? arr.map((d) => String(d)).filter(Boolean) : [];

function readModelDates() {
  let dates = [
    ...toDateList(weather.model_dates),
    ...toDateList(weather.model_recommended_dates),
  ];
  if (dates.length) return [...new Set(dates)];

  const candidates = [
    'Call Event Date Model API1',
    'Call Event Date Model API',
    'Call Event Date Model API2',
  ];

  for (const nodeName of candidates) {
    try {
      const items = $items(nodeName, 0, 0);
      const resp = Array.isArray(items) && items[0] ? (items[0].json || {}) : {};
      const result = resp.result || {};
      dates = toDateList(result.recommended_dates);
      if (dates.length) return [...new Set(dates)];
    } catch (e) {
      // ignore
    }
  }

  return [];
}

const modelDates = readModelDates();

let weatherRows = [];

if (Array.isArray(weather.suggested_dates_weather)) {
  weatherRows = weather.suggested_dates_weather;
} else if (
  weather.suggested_dates_weather &&
  typeof weather.suggested_dates_weather === 'object'
) {
  weatherRows = Object.values(weather.suggested_dates_weather).filter((v) => v && v.date);
} else {
  weatherRows = Object.keys(weather)
    .filter((key) => key.startsWith('suggested_dates_weather'))
    .map((key) => weather[key])
    .filter((v) => v && v.date);
}

const topN = Math.min(30, Math.max(1, Math.floor(Number(weather.top_n_dates ?? 10))));
const byDate = new Map(weatherRows.map((row) => [String(row.date), row]));

const combined = [];

for (const row of weatherRows) {
  const date = String(row.date);
  combined.push({
    date,
    source: modelDates.includes(date) ? 'weather+model' : 'weather',
    precipitation_probability_max: row.precipitation_probability_max ?? null,
    temperature_2m_max: row.temperature_2m_max ?? null,
    weather_score: row.weather_score ?? null,
  });
}

for (const date of modelDates) {
  if (!combined.find((x) => x.date === date)) {
    const w = byDate.get(date);
    combined.push({
      date,
      source: 'model',
      precipitation_probability_max: w?.precipitation_probability_max ?? null,
      temperature_2m_max: w?.temperature_2m_max ?? null,
      weather_score: w?.weather_score ?? null,
    });
  }
}

const sourceRank = (s) => (s === 'weather+model' ? 2 : s === 'weather' ? 1 : 0);

const ranked = combined
  .sort((a, b) => Number(b.weather_score ?? -1) - Number(a.weather_score ?? -1) || sourceRank(b.source) - sourceRank(a.source))
  .slice(0, topN);

return [
  {
    json: {
      ...weather,
      model_dates: modelDates,
      combined_candidates: ranked,
      recommended_dates: ranked.map((x) => x.date),
      next_recommended_date: ranked[0]?.date || null,
      count: ranked.length,
    },
  },
];
